SELECT name, current_occupancy
FROM parking_zones
WHERE is_active = 1;

SELECT name, (current_occupancy * 100.0 / capacity) AS occupancy_percentage
FROM parking_zones
WHERE (current_occupancy * 100.0 / capacity) > 50.0;

SELECT AVG(total_amount) AS average_total_amount
FROM (
    SELECT zone_id, SUM(amount) AS total_amount
    FROM transactions
    GROUP BY zone_id
) AS zone_totals;

SELECT COUNT(*) AS total_active_zones
FROM parking_zones
WHERE is_active = 1;

SELECT zone_id
FROM parking_zones
WHERE current_occupancy = (SELECT MAX(current_occupancy) FROM parking_zones);

SELECT available_spots 
FROM parking_availability 
WHERE zone_id = 1;

SELECT COUNT(zone_id) AS active_zones_with_capacity
FROM parking_zones
WHERE is_active = 1 AND current_occupancy < capacity;

SELECT method_name
FROM payment_methods
WHERE is_enabled = 1;

SELECT name, current_occupancy, capacity 
FROM parking_zones 
ORDER BY current_occupancy DESC;
